#include <stdio.h>
#include <stdlib.h>
#include <string.h>
typedef struct Point {
    int x, y;
} Point;

int manhattan_distance(Point p1, Point p2) {
    return abs(p1.x - p2.x) + abs(p1.y - p2.y);
}

int main() {
    int Q;
    scanf("%d", &Q);
    Point* points = (Point*) malloc(Q * sizeof(Point));
    int* indices = (int*) malloc(Q * sizeof(int));
    int answer = 0;
    for (int i = 0; i < Q; i++) {
        char query;
        scanf(" %c", &query);
        if (query == '+') {
            int x, y;
            scanf("%d %d", &x, &y);
            x ^= answer;
            y ^= answer;
            points[i].x = x;
            points[i].y = y;
            indices[i] = i;
        } else if (query == '-') {
            int n;
            scanf("%d", &n);
            n ^= answer;
            points[n].x = -1;
            points[n].y = -1;
        } else if (query == '?') {
            int x, y;
            scanf("%d %d", &x, &y);
            x ^= answer;
            y ^= answer;
            int max_distance = 0;
            for (int j = 0; j < Q; j++) {
                if (points[j].x != -1 && points[j].y != -1) {
                    int distance = manhattan_distance((Point) {x, y}, points[j]);
                    max_distance = (distance > max_distance) ? distance : max_distance;
                }
            }
            printf("%d\n", max_distance);
            answer = max_distance;
        }
    }
    free(points);
    free(indices);
    return 0;
}

