import java.util.Scanner;
public class Main {
    static class Point {
        int x, y;
        Point(int x, int y) {
            this.x = x;
            this.y = y;
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int Q = scanner.nextInt();
        Point[] points = new Point[Q];
        int[] indices = new int[Q];
        int answer = 0;
        for (int i = 0; i < Q; i++) {
            char query = scanner.next().charAt(0);
            if (query == '+') {
                int x = scanner.nextInt();
                int y = scanner.nextInt();
                x ^= answer;
                y ^= answer;
                points[i] = new Point(x, y);
                indices[i] = i;
            } else if (query == '-') {
                int n = scanner.nextInt();
                n ^= answer;
                points[n].x = -1;
                points[n].y = -1;
            } else if (query == '?') {
                int x = scanner.nextInt();
                int y = scanner.nextInt();
                x ^= answer;
                y ^= answer;
                int max_distance = 0;
                for (int j = 0; j < Q; j++) {
                    if (points[j] != null && points[j].x != -1 && points[j].y != -1) {
                        int distance = Math.abs(x - points[j].x) + Math.abs(y - points[j].y);
                        max_distance = Math.max(distance, max_distance);
                    }
                }
                System.out.println(max_distance);
                answer = max_distance;
            }
        }
    }
}

